function navavishkar_stay_payment_table_insert(&$error_message = '') {
	global $Translation;

	// mm: can member insert record?
	$arrPerm = getTablePermissions('navavishkar_stay_payment_table');
	if(!$arrPerm['insert']) {
		$error_message = $Translation['no insert permission'];
		return false;
	}

	// automatic navavishakr_stay_details if passed as filterer
	if(Request::val('filterer_navavishakr_stay_details')) {
		$_REQUEST['navavishakr_stay_details'] = Request::val('filterer_navavishakr_stay_details');
	}

	$data = [
		'username' => parseCode('<%%creatorUsername%%>', true),
		'payment_status' => Request::val('payment_status', 'Pending'),
		'amount' => Request::val('amount', ''),
		'additional_facilities_provided' => Request::val('additional_facilities_provided', ''),
		'payment_img' => Request::fileUpload('payment_img', [
			'maxSize' => 102400,
			'types' => 'jpg|jpeg|gif|png|webp',
			'noRename' => false,
			'dir' => '',
			'success' => function($name, $selected_id) {
			},
			'failure' => function($selected_id, $fileRemoved) {
				if(!strlen(Request::val('SelectedID'))) return '';

				/* for empty upload fields, when saving a copy of an existing record, copy the original upload field */
				return existing_value('navavishkar_stay_payment_table', 'payment_img', Request::val('SelectedID'));
			},
		]),
		'remarks' => br2nl(Request::val('remarks', '')),
		'created_by' => parseCode('<%%creatorUsername%%>', true),
		'created_at' => parseCode('<%%creationDateTime%%>', true),
	];


	// automatic navavishakr_stay_details if passed as filterer
	if(Request::val('filterer_navavishakr_stay_details')) {
		$data['navavishakr_stay_details'] = Request::val('filterer_navavishakr_stay_details');
	}
	// record owner is current user
	$recordOwner = getLoggedMemberID();

	$recID = tableInsert('navavishkar_stay_payment_table', $data, $recordOwner, $error_message);

	// if this record is a copy of another record, copy children if applicable
	if(strlen(Request::val('SelectedID')) && $recID !== false)
		navavishkar_stay_payment_table_copy_children($recID, Request::val('SelectedID'));

	return $recID;
}

function navavishkar_stay_payment_table_copy_children($destination_id, $source_id) {
	global $Translation;
	$requests = []; // array of curl handlers for launching insert requests
	$eo = ['silentErrors' => true];
	$safe_sid = makeSafe($source_id);
	$currentUsername = getLoggedMemberID();
	$errorMessage = '';

	// launch requests, asynchronously
	curl_batch($requests);
}

function navavishkar_stay_payment_table_delete($selected_id, $AllowDeleteOfParents = false, $skipChecks = false) {
	// insure referential integrity ...
	global $Translation;
	$selected_id = makeSafe($selected_id);

	// mm: can member delete record?
	if(!check_record_permission('navavishkar_stay_payment_table', $selected_id, 'delete')) {
		return $Translation['You don\'t have enough permissions to delete this record'];
	}

	// hook: navavishkar_stay_payment_table_before_delete
	if(function_exists('navavishkar_stay_payment_table_before_delete')) {
		$args = [];
		if(!navavishkar_stay_payment_table_before_delete($selected_id, $skipChecks, getMemberInfo(), $args))
			return $Translation['Couldn\'t delete this record'] . (
				!empty($args['error_message']) ?
					'<div class="text-bold">' . strip_tags($args['error_message']) . '</div>'
					: ''
			);
	}

	// delete file stored in the 'payment_img' field
	$res = sql("SELECT `payment_img` FROM `navavishkar_stay_payment_table` WHERE `id`='{$selected_id}'", $eo);
	if($row = @db_fetch_row($res)) {
		if($row[0] != '') {
			@unlink(getUploadDir('') . $row[0]);
		}
	}

	sql("DELETE FROM `navavishkar_stay_payment_table` WHERE `id`='{$selected_id}'", $eo);

	// hook: navavishkar_stay_payment_table_after_delete
	if(function_exists('navavishkar_stay_payment_table_after_delete')) {
		$args = [];
		navavishkar_stay_payment_table_after_delete($selected_id, getMemberInfo(), $args);
	}

	// mm: delete ownership data
	sql("DELETE FROM `membership_userrecords` WHERE `tableName`='navavishkar_stay_payment_table' AND `pkValue`='{$selected_id}'", $eo);
}

function navavishkar_stay_payment_table_update(&$selected_id, &$error_message = '') {
	global $Translation;

	// mm: can member edit record?
	if(!check_record_permission('navavishkar_stay_payment_table', $selected_id, 'edit')) return false;

	$data = [
		'payment_status' => Request::val('payment_status', ''),
		'amount' => Request::val('amount', ''),
		'additional_facilities_provided' => Request::val('additional_facilities_provided', ''),
		'payment_img' => Request::fileUpload('payment_img', [
			'maxSize' => 102400,
			'types' => 'jpg|jpeg|gif|png|webp',
			'noRename' => false,
			'dir' => '',
			'id' => $selected_id,
			'success' => function($name, $selected_id) {
			},
			'removeOnSuccess' => true,
			'removeOnRequest' => true,
			'remove' => function($selected_id) {
				// delete old file from server
				$oldFile = existing_value('navavishkar_stay_payment_table', 'payment_img', $selected_id);
				if(!$oldFile) return;

				@unlink(getUploadDir('') . $oldFile);
			},
			'failure' => function($selected_id, $fileRemoved) {
				if($fileRemoved) return '';
				return existing_value('navavishkar_stay_payment_table', 'payment_img', $selected_id);
			},
		]),
		'remarks' => br2nl(Request::val('remarks', '')),
		'last_updated_by' => parseCode('<%%editorUsername%%>', false),
		'last_updated_at' => parseCode('<%%editingDateTime%%>', false),
	];

	// get existing values
	$old_data = getRecord('navavishkar_stay_payment_table', $selected_id);
	if(is_array($old_data)) {
		$old_data = array_map('makeSafe', $old_data);
		$old_data['selectedID'] = makeSafe($selected_id);
	}

	$data['selectedID'] = makeSafe($selected_id);

	// hook: navavishkar_stay_payment_table_before_update
	if(function_exists('navavishkar_stay_payment_table_before_update')) {
		$args = ['old_data' => $old_data];
		if(!navavishkar_stay_payment_table_before_update($data, getMemberInfo(), $args)) {
			if(isset($args['error_message'])) $error_message = $args['error_message'];
			return false;
		}
	}

	$set = $data; unset($set['selectedID']);
	foreach ($set as $field => $value) {
		$set[$field] = ($value !== '' && $value !== NULL) ? $value : NULL;
	}

	if(!update(
		'navavishkar_stay_payment_table',
		backtick_keys_once($set),
		['`id`' => $selected_id],
		$error_message
	)) {
		echo $error_message;
		echo '<a href="navavishkar_stay_payment_table_view.php?SelectedID=' . urlencode($selected_id) . "\">{$Translation['< back']}</a>";
		exit;
	}


	update_calc_fields('navavishkar_stay_payment_table', $data['selectedID'], calculated_fields()['navavishkar_stay_payment_table']);

	// hook: navavishkar_stay_payment_table_after_update
	if(function_exists('navavishkar_stay_payment_table_after_update')) {
		if($row = getRecord('navavishkar_stay_payment_table', $data['selectedID'])) $data = array_map('makeSafe', $row);

		$data['selectedID'] = $data['id'];
		$args = ['old_data' => $old_data];
		if(!navavishkar_stay_payment_table_after_update($data, getMemberInfo(), $args)) return;
	}

	// mm: update record update timestamp
	set_record_owner('navavishkar_stay_payment_table', $selected_id);
}

